"use client";

import { FormEvent, useEffect, useState } from "react";
import { addDoc, collection, onSnapshot, orderBy, query, serverTimestamp } from "firebase/firestore";
import toast from "react-hot-toast";
import { db } from "@/lib/firebase";
import { Review } from "@/lib/types";

export default function ReviewsPage() {
  const [reviews, setReviews] = useState<Review[]>([]);
  const [name, setName] = useState("");
  const [comment, setComment] = useState("");
  const [rating, setRating] = useState(5);

  useEffect(() => {
    const q = query(collection(db, "reviews"), orderBy("createdAt", "desc"));
    const unsub = onSnapshot(q, (snap) => {
      setReviews(snap.docs.map((doc) => ({ id: doc.id, ...(doc.data() as Omit<Review, "id">) })));
    });
    return () => unsub();
  }, []);

  async function submitReview(e: FormEvent) {
    e.preventDefault();
    await addDoc(collection(db, "reviews"), { name, comment, rating, createdAt: serverTimestamp() });
    toast.success("Review submitted");
    setName("");
    setComment("");
    setRating(5);
  }

  return (
    <section className="mx-auto grid max-w-6xl gap-8 px-4 py-10 md:grid-cols-2">
      <form onSubmit={submitReview} className="rounded-xl border border-zinc-800 bg-zinc-900 p-5">
        <h1 className="text-2xl font-bold">Reviews</h1>
        <input className="mt-4 w-full rounded bg-zinc-800 p-3" placeholder="Your name" value={name} onChange={(e) => setName(e.target.value)} required />
        <textarea className="mt-3 w-full rounded bg-zinc-800 p-3" placeholder="Comment" value={comment} onChange={(e) => setComment(e.target.value)} required />
        <select className="mt-3 w-full rounded bg-zinc-800 p-3" value={rating} onChange={(e) => setRating(Number(e.target.value))}>
          {[5, 4, 3, 2, 1].map((r) => (
            <option key={r} value={r}>{r} Stars</option>
          ))}
        </select>
        <button className="mt-3 rounded bg-amber-400 px-4 py-2 font-semibold text-zinc-900">Submit</button>
      </form>
      <div className="space-y-3">
        {reviews.map((review) => (
          <article key={review.id} className="rounded-lg border border-zinc-800 bg-zinc-900 p-4">
            <h3 className="font-semibold">{review.name}</h3>
            <p className="text-amber-400">{"★".repeat(review.rating)}</p>
            <p className="mt-1 text-sm text-zinc-300">{review.comment}</p>
          </article>
        ))}
      </div>
    </section>
  );
}
